document.addEventListener('DOMContentLoaded', function() {

var headbodyTag = document.querySelector(".dt-emc-header");
var headaudienceType = headbodyTag.getAttribute("data-audtype");
var headtrainingcred = headbodyTag.getAttribute("data-tcredits");

if(headaudienceType != "Guest" && headaudienceType != "GUEST" && headaudienceType != "Internal" && headaudienceType != "INTERNAL"){
    document.querySelector(".mylearning .tc").setAttribute("style", "flex:1;");
    if(headtrainingcred != "null")
    	document.querySelector(".mylearning .tc p").innerHTML = "Training Credits: " + headtrainingcred;
}
else
    document.querySelector(".mylearning .tc").setAttribute("style", "display:none;");

// Text colors based on background color of text section
    const textbackgrounds = document.querySelector('.mylearning .text-section');

        const mylearningtexts = textbackgrounds.querySelectorAll('.mylearning .text-section h1, .mylearning .text-section .tc');
        mylearningtexts.forEach(mylearningtext => {
            adjustTextColor(mylearningtext, textbackgrounds);
        });
        const breadcrumbcontents = document.querySelectorAll('.mylearning .breadcrumb a, .mylearning .breadcrumb span, .mylearning .breadcrumb i, .mylearning .breadcrumb li');
		breadcrumbcontents.forEach(breadcrumbcontent => {
        	adjustTextColor(breadcrumbcontent, textbackgrounds);
        });
        const breadcrumbItems = document.querySelectorAll('.mylearning .dds__breadcrumb__item');
                breadcrumbItems.forEach((item, index) => {
          	    	if (index !== breadcrumbItems.length - 1) {
            			item.classList.add('apply-after-style'); // Add a class to all except the last item
            			adjustTextColor(item, textbackgrounds);
          			}
        });
        function adjustTextColor(element, background) {
            const backgroundColor = window.getComputedStyle(textbackgrounds).backgroundColor;
            const rgb = backgroundColor.match(/\d+/g).map(Number);
            const brightness = (rgb[0] * 299 + rgb[1] * 587 + rgb[2] * 114) / 1000;

            if (brightness < 128) {
                element.style.color = 'white';
            } else {
                element.style.color = 'black';
            }
        }    
});

