var $jq = jQuery.noConflict(); 

try{
    var sso_cookie=getCookie('RSAIdentityType');
    //alert(sso_cookie);
    var currentUserRole;
    var arr1 = sso_cookie.split(',');
	if (arr1.length == 1) {
		var rsaType = arr1[0];

		if ((rsaType.toLowerCase() == "C".toLowerCase())
				|| (rsaType.toLowerCase() == "X".toLowerCase())) {
			currentUserRole = "C";
		} else if (rsaType.toLowerCase() == "P".toLowerCase()) {
			currentUserRole = "P";
		} else if ((rsaType.toLowerCase() == "E".toLowerCase())
			    || (rsaType.toLowerCase() == "V".toLowerCase())
			    || (rsaType.toLowerCase() == "T".toLowerCase())) {
			currentUserRole = "E";
		}
	} else if (arr1.length == 2) {
		var CorPFirst = arr1[0];
		var CorPSecond = arr1[1];

		if ((CorPFirst.toLowerCase() == "P".toLowerCase() && CorPSecond
				.toLowerCase() == "C".toLowerCase())
				|| (CorPFirst.toLowerCase() == "C".toLowerCase() && CorPSecond
						.toLowerCase() == "P".toLowerCase())) {
			currentUserRole = "P";
		}
	}
}catch(e){
    console.log(e);
}

function getCookie(cname) {
    var name = cname + "=";
    var ca = document.cookie.split(';');
    for(var i = 0; i <ca.length; i++) {
        var c = ca[i];
        while (c.charAt(0)==' ') {
            c = c.substring(1);
        }
        if (c.indexOf(name) == 0) {
            return c.substring(name.length,c.length);
        }
    }
    return "";
}


$jq(document).ready(function() {
    $jq("a").click(function() {
        //Do stuff when clicked
    	var title = $jq(this).attr('title');
    	if (title == "cookiedelete")
    		{

    			var name = "ACTSESSION";
    			var path = "/";
    			var domain = ".emc.com";    				
    				delete_cookie(name, path, domain); 
    			name = "CTSESSION";
    				delete_cookie(name, path, domain);
    			name = "PORTALACTSESSION";
    				delete_cookie(name, path, domain);
    			window.location.href = ("/content/emc/index_login.html");
    		}
    });
});


/*function deleteAllCookies() {
	var domain = "https://education.emc.com";    var path = path || "/";
    document.cookie = name + "=; expires=" + +new Date + "; domain=" + domain + "; path=" + path;    
	}*/


function delete_cookie( name, path, domain ) {
  if( getCookie( name ) ) {
    document.cookie = name + "=" +
      ((path) ? ";path="+path:"")+
      ((domain)?";domain="+domain:"") +
      ";expires=Thu, 01 Jan 1970 00:00:01 GMT";
  }
}

function getCookie(name) {
  var value = "; " + document.cookie;
  var parts = value.split("; " + name + "=");
  if (parts.length == 2) return parts.pop().split(";").shift();
}

