348		private void createCookie(HttpServletRequest pHttpRequest, HttpServletResponse pHttpResponse, String pCookieValue,
349								  String pCookieName, int maxAge) {
350			try {
351				if (!isValidCookieName(pCookieName)) {
352					LOG.warn("Invalid cookie name: " + pCookieName);
353					return;
354				}
355	
356				String sanitizedValue = null;
357				if (pCookieValue != null) {
358					sanitizedValue = StringUtils.strip(pCookieValue, "\"");
359					if (!isSafeCookieValue(sanitizedValue)) {
360						LOG.warn("Unsafe cookie value detected for: " + pCookieName);
361						return;
362					}
363				}
364	
365				String domainName = getDomainName(pHttpRequest);
366				LOG.info("domainName:" + domainName);
367	
368				if (domainName == null || domainName.isEmpty()) {
369					domainName = "localhost";
370				} else if (!isValidDomain(domainName)) {
371					LOG.warn("Invalid domain detected: " + domainName);
372					return;
373				}
374	
375				Cookie cookie = new Cookie(pCookieName, sanitizedValue);
376				cookie.setDomain(domainName);
377				cookie.setPath("/");
378				cookie.setMaxAge(maxAge);
379	
380				pHttpResponse.addCookie(cookie);
381				LOG.info("Cookie created: " + pCookieName);
382			} catch (Exception e) {
383				LOG.error("Exception in createCookie: " + e.getMessage(), e);
384			}
385		}
