387		public static void deleteCookie(HttpServletRequest request, HttpServletResponse response, String cookieName) {
388			try {
389				LOG.info("Delete cookie triggered for: " + cookieName);
390	
391				if (!isValidCookieName(cookieName)) {
392					LOG.warn("Invalid cookie name for deletion: " + cookieName);
393					return;
394				}
395	
396				String domainName;
397				try {
398					domainName = getDomainName(request);
399					if (domainName == null || domainName.isEmpty()) {
400						domainName = "localhost";
401					} else if (!isValidDomain(domainName)) {
402						LOG.warn("Invalid domain for cookie deletion: " + domainName);
403						return;
404					}
405				} catch (MalformedURLException e) {
406					LOG.warn("Could not determine domain for cookie deletion", e);
407					domainName = "localhost";
408				}
409	
410				Cookie cookie = new Cookie(cookieName, null);
411				cookie.setMaxAge(0);
412				cookie.setPath("/");
413				cookie.setDomain(domainName);
414	
415				response.addCookie(cookie);
416				LOG.info("Cookie deleted: " + cookieName);
417			} catch (Exception e) {
418				LOG.error("Exception in deleteCookie: " + e.getMessage(), e);
419			}
420		}
