422		private void deleteAllCookie(HttpServletRequest pHttpRequest, HttpServletResponse pHttpResponse) {
423			try {
424				// First, get all cookie names from the request
425				List<String> validCookieNames = new ArrayList<>();
426				Cookie[] requestCookies = pHttpRequest.getCookies();
427	
428				if (requestCookies != null) {
429					for (Cookie cookie : requestCookies) {
430						if (cookie != null && cookie.getName() != null) {
431							String name = cookie.getName();
432							// Only collect valid cookie names
433							if (name.matches("^[a-zA-Z0-9!#$%&'*+.^_`|~-]+$")) {
434								validCookieNames.add(name);
435							} else {
436								LOG.warn("Ignoring cookie with invalid name in request");
437							}
438						}
439					}
440				}
441	
442				// Extract safe domain
443				String safeDomain = null;
444				try {
445					String serverName = pHttpRequest.getServerName();
446					if (serverName != null && !serverName.isEmpty()) {
447						if (serverName.contains(".")) {
448							String[] parts = serverName.split("\\.");
449							if (parts.length > 1) {
450								StringBuilder sb = new StringBuilder();
451								safeDomain = sb.append(parts[parts.length - 2])
452										.append(".")
453										.append(parts[parts.length - 1])
454										.toString();
455							} else {
456								safeDomain = serverName;
457							}
458						} else {
459							safeDomain = serverName;
460						}
461	
462						// Validate domain
463						if (!safeDomain.matches("^[a-zA-Z0-9.-]+$") || safeDomain.contains("..")) {
464							LOG.warn("Invalid domain: " + safeDomain);
465							safeDomain = "localhost";
466						}
467					} else {
468						safeDomain = "localhost";
469					}
470				} catch (Exception e) {
471					LOG.warn("Error determining domain, using localhost", e);
472					safeDomain = "localhost";
473				}
474	
475				// Now delete all valid cookies with a safe domain
476				for (String cookieName : validCookieNames) {
477					try {
478						// Create a completely new cookie with controlled parameters
479						Cookie deleteCookie = new Cookie(cookieName, null);
480						deleteCookie.setMaxAge(0);
481						deleteCookie.setPath("/");
482						deleteCookie.setDomain(safeDomain);
483	
484						pHttpResponse.addCookie(deleteCookie);
485						LOG.info("Deleted cookie: " + cookieName);
486					} catch (Exception e) {
487						LOG.warn("Failed to delete cookie: " + cookieName, e);
488					}
489				}
490			} catch (Exception e) {
491				LOG.error("Exception in deleteAllCookie", e);
492			}
493		}
494	
495		private static boolean isValidCookieName(String cookieName) {
496			return cookieName != null &&
497					!cookieName.isEmpty() &&
498					cookieName.length() <= 256 &&
499					Pattern.matches("^[a-zA-Z0-9!#$%&'*+.^_`|~-]+$", cookieName);
500		}
501	
502		private static boolean isValidDomain(String domain) {
503			return domain != null &&
504					!domain.isEmpty() &&
505					domain.length() <= 253 &&
506					Pattern.matches("^[a-zA-Z0-9.-]+$", domain) &&
507					!domain.contains("..");
508		}
509	
510		private static boolean isSafeCookieValue(String value) {
511			return value == null ||
512					(!value.contains("\r") &&
513							!value.contains("\n") &&
514							Pattern.matches("^[a-zA-Z0-9_\\-\\.@,;:+*=\\s]*$", value));
515		}
516	
517		private static String getDomainName(HttpServletRequest pHttpRequest) throws MalformedURLException {
518			URL url = new URL(pHttpRequest.getRequestURL().toString());
519			String domainName = "";
520			String hostName = url.getHost();
521			LOG.info("hostname:" + hostName);
522	
523			if (hostName != null) {
524				if (hostName.contains(".")) {
525					String[] hostNameStrArr = hostName.split("\\.");
526					int length = hostNameStrArr.length;
527					if (length > 1) {
528						StringBuilder sb = new StringBuilder();
529						domainName = sb.append(hostNameStrArr[length - 2])
530								.append(".")
531								.append(hostNameStrArr[length - 1]).toString();
532					}
533				} else if (hostName.contains(":")) {
534					String[] hostNameStrArr = hostName.split("\\:");
535					int length = hostNameStrArr.length;
536					if (length > 0) {
537						domainName = hostNameStrArr[0];
538					}
539				} else {
540					domainName = hostName;
541				}
542			}
543	
544			return domainName;
545		}
