	public String sanitizeCookieValue(String cookieValue) {
		if (cookieValue == null || cookieValue.isEmpty()) {
			return null;
		}

		// Remove any characters that aren't alphanumeric or ., @, -, _
		String sanitized = cookieValue.replaceAll("[^a-zA-Z0-9.@\\-_]", "");

		// Optionally, limit the length
		int maxLength = 170; // Adjust this value as needed
		if (sanitized.length() > maxLength) {
			sanitized = sanitized.substring(0, maxLength);
		}

		return sanitized;
	}

